# Bactérie 2 = receiver, espèce 4 = Z (output)
LOC_INPUT  = (1, 1)   # bact 1, espèce X
LOC_OUTPUT = (1, 2)   # bact 2, espèce Z
T_WINDOW   = (100.0, 100000.0)

# ==============================================================================
# 3. FONCTIONS UTILITAIRES
# ==============================================================================
function get_signal(data, loc, t_window)
    t   = data["time"]                          # String key
    idx = findall(x -> t_window[1] <= x <= t_window[2], t)
    isempty(idx) && return nothing
    return data["data"][idx, loc[1], loc[2]]    # [temps, bactérie, espèce]
end

function calculate_metrics(filepath)
    !isfile(filepath) && return (NaN, NaN)
    try
        data  = load_object(filepath)
        s_in  = get_signal(data, LOC_INPUT,  T_WINDOW)
        s_out = get_signal(data, LOC_OUTPUT, T_WINDOW)
        (isnothing(s_in) || isnothing(s_out)) && return (NaN, NaN)

        # Distorsion : MSE sur signaux normalisés
        σ_in  = std(s_in)
        σ_out = std(s_out)
        if σ_in < 1e-10 || σ_out < 1e-10
            return (NaN, NaN)   # Signal constant, pas exploitable
        end
        z_in  = (s_in  .- mean(s_in))  ./ σ_in
        z_out = (s_out .- mean(s_out)) ./ σ_out
        D     = mean((z_in .- z_out).^2)

        mi   = RateDistortionBiology.mutual_information_continuous(s_in, s_out)
        cost = mean(s_out)
        J    = mi - (ALPHA_PARAM * cost)

        return (D, J)
    catch e
        println("   ⚠️ Erreur : $filepath — $e")
        return (NaN, NaN)
    end
end

# ==============================================================================
# 4. BOUCLE PRINCIPALE
# ==============================================================================
n_configs = length(PARAM_DIRS)
results_D = fill(NaN, n_configs, NUM_SIMS)
results_J = fill(NaN, n_configs, NUM_SIMS)

println("🔄 Démarrage de l'analyse...")

for (c_idx, folder) in enumerate(PARAM_DIRS)
    println("   📂 Config $c_idx : $folder")
    for s in 1:NUM_SIMS
        path = joinpath(BASE_DIR, folder, "sim_$s.jld2")
        d, j = calculate_metrics(path)
        results_D[c_idx, s] = d
        results_J[c_idx, s] = j
    end
end

# ==============================================================================
# 5. STATISTIQUES PAR CONFIGURATION
# ==============================================================================
final_mean_D = zeros(n_configs)
final_std_D  = zeros(n_configs)
final_mean_J = zeros(n_configs)
final_std_J  = zeros(n_configs)

for i in 1:n_configs
    clean_D = filter(!isnan, results_D[i, :])
    clean_J = filter(!isnan, results_J[i, :])
    n = length(clean_D)
    if n > 0
        final_mean_D[i] = mean(clean_D)
        final_mean_J[i] = mean(clean_J)
        final_std_D[i]  = n > 1 ? std(clean_D) : 0.0
        final_std_J[i]  = n > 1 ? std(clean_J) : 0.0
    else
        final_mean_D[i] = NaN
        final_mean_J[i] = NaN
    end
end

println("\n📊 Résultats par config :")
for i in 1:n_configs
    @printf("   v_max=%.4f  →  D=%.4f ± %.4f  |  J=%.4f ± %.4f\n",
            V_MAX_VALUES[i], final_mean_D[i], final_std_D[i],
            final_mean_J[i], final_std_J[i])
end

