# ==============================================================================
# 2. Interpolation MI vs v_max (croissante)
# ==============================================================================
# Tri par v_max croissant et suppression des doublons
sorted_indices = sortperm(vmax_m)
vmax_sorted = vmax_m[sorted_indices]
mi_sorted = mi[sorted_indices]

# Suppression des doublons dans vmax_sorted (obligatoire pour l'interpolation)
unique_indices = unique(i -> vmax_sorted[i], 1:length(vmax_sorted))
vmax_unique = vmax_sorted[unique_indices]
mi_unique = mi_sorted[unique_indices]

# Interpolation linéaire
itp_mi_vmax = linear_interpolation(vmax_unique, mi_unique, extrapolation_bc=Flat())

# ==============================================================================
# 3. Interpolation nl vs MI (décroissante)
# ==============================================================================
# Création de paires (MI, nl) et tri par MI croissant
mi_nl_pairs = collect(zip(mi_vs_nl, nl_vs_mi))
sort!(mi_nl_pairs, by = first)  # Tri par MI croissant

# Extraction des vecteurs triés et suppression des doublons
mi_sorted_nl = [pair[1] for pair in mi_nl_pairs]
nl_sorted = [pair[2] for pair in mi_nl_pairs]

# Suppression des doublons dans mi_sorted_nl
unique_indices_nl = unique(i -> mi_sorted_nl[i], 1:length(mi_sorted_nl))
mi_unique_nl = mi_sorted_nl[unique_indices_nl]
nl_unique = nl_sorted[unique_indices_nl]

# Vérification : nl doit diminuer quand MI augmente
if nl_unique[1] > nl_unique[end]  # Si décroissant, on inverse
    nl_unique = nl_unique
    mi_unique_nl = mi_unique_nl
end

# Interpolation linéaire
itp_nl_mi = linear_interpolation(mi_unique_nl, nl_unique, extrapolation_bc=Flat())

