using LsqFit

# ==============================================================================
# 6. Fit exponentiel décroissant sur nl vs v_max
# ==============================================================================
# Modèle exponentiel : nl(v_max) = A * exp(-k * v_max) + C
@. model(v, p) = p[1] * exp(-p[2] * v) + p[3]

# Estimation initiale des paramètres [A, k, C]
p0 = [maximum(nl_interp) - minimum(nl_interp),  # A ≈ amplitude
      0.5,                                      # k ≈ taux de décroissance (à ajuster)
      minimum(nl_interp)]                       # C ≈ offset

# Fit des données interpolées
fit = curve_fit(model, vmax_range, nl_interp, p0)
p_opt = fit.param  # Paramètres optimaux [A, k, C]

# Génération des valeurs du fit pour le tracé
nl_fit = model(vmax_range, p_opt)

# Équation du fit pour affichage
fit_eq = "nl = $(round(p_opt[1], digits=3)) * exp(-$(round(p_opt[2], digits=3)) * v_max) + $(round(p_opt[3], digits=3))"

# Ajout du fit sur p2
plot!(p2,
      vmax_range, nl_fit,
      label = "Fit exponentiel: $fit_eq",
      linewidth = 2,
      linestyle = :dash,
      color = :red
)

# Affichage de l'équation sur le graphique
annotate!(p2,
          0.5 * maximum(vmax_range),
          0.9 * maximum(nl_interp),
          text(fit_eq, 10, :left, :top, :red)
)

# Mise à jour du titre
plot!(p2, title = "Noise Level vs v_max (avec fit exponentiel)")


