using Plots, Interpolations, Statistics, LsqFit


# =============================================
# 1. FIT EXPONENTIEL (y = A*exp(-k*x) + C)
# =============================================
@. model(x, p) = p[1] * exp(p[2] * x) + p[3]  # Modèle exponentiel
p0 = [maximum(vmax_m), 1.0, minimum(vmax_m)]   # Estimation initiale [A, k, C]
fit = curve_fit(model, nl, vmax_m, p0)
p_opt = fit.param  # Paramètres optimaux [A, k, C]

# Génération des valeurs du fit pour le tracé
nl_fit_range = range(minimum(nl), maximum(nl), length=100)
vmax_fit = model(nl_fit_range, p_opt)

# Équation du fit (arrondie à 2 décimales)
fit_eq = "y = $(round(p_opt[1], digits=2)) * exp($(round(p_opt[2], digits=2)) * x) + $(round(p_opt[3], digits=2))"

# =============================================
# 2. TENDANCE INTERPOLÉE + FIT EXPONENTIEL
# =============================================
# Tri des données
sorted_indices = sortperm(nl)
nl_sorted = nl[sorted_indices]
vmax_sorted = vmax_m[sorted_indices]

# Interpolation linéaire
itp = linear_interpolation(nl_sorted, vmax_sorted, extrapolation_bc=Flat())
nl_range = range(minimum(nl), maximum(nl), length=100)
vmax_interp = itp.(nl_range)

# Tracé
p_trend = plot(
    nl_range, vmax_interp,
    label = "Tendance interpolée",
    xlabel = "Noise Level (K_transl)",
    ylabel = "v_max",
    title = "v_max vs Noise Level (Interpolation + Fit Exponentiel)",
    linewidth = 2,
    color = :blue,
    grid = true,
    framestyle = :box,
    size = (800, 600)
)

# Superposition des points bruts
scatter!(p_trend, nl, vmax_m,
    label = "Données brutes",
    color = :red,
    markersize = 5,
    alpha = 0.6
)

# Superposition du fit exponentiel
plot!(p_trend, nl_fit_range, vmax_fit,
    label = "Fit exponentiel: $fit_eq",
    linewidth = 2,
    color = :green,
    linestyle = :dash
)

# Affichage de l'équation
annotate!(p_trend, 0.7 * maximum(nl), 0.9 * maximum(vmax_m),
    text(fit_eq, 10, :left, :top, :green)
)

savefig(p_trend, "vmax_vs_noiselevel_trend_with_fit.png")

